INSERT INTO product (name, price, description, tax_code) VALUES ('Arc Headphones', 249.00, 'Engineered for silence. Adaptive noise cancellation that maps your environment in real time, forty-hour battery, and drivers tuned in an anechoic chamber. Not headphones that block the world — headphones that make it irrelevant.

The ear cups are machined from a single billet of aerospace aluminum, then lined with slow-recovery memory foam and covered in full-grain leather. They do not creak. They do not flex. They sit on your head like something permanent.', 'AUDIO_EQUIPMENT');

INSERT INTO product (name, price, description, tax_code) VALUES ('Carbon Keyboard', 189.00, 'Every keystroke is load-bearing. Aircraft-grade aluminum chassis, hot-swap mechanical switches, and a layout refined over three years of daily use. Most keyboards are forgotten. This one becomes a habit.

The base plate is milled from 6061 aluminum and weighted with a brass accent bar underneath — 1.4kg total, enough that it does not move. The switches are factory-lubed linear reds with a 45g actuation force: fast, quiet, and consistent from the first key to the last.', 'ELECTRONICS');

INSERT INTO product (name, price, description, tax_code) VALUES ('Arc Display', 699.00, 'A 27-inch panel built around the assumption that you will stare at it for ten hours a day. 1440p at 165Hz, factory-calibrated to Delta E < 1, and a stand that adjusts to the millimeter. Designed for people who notice when something is slightly off.

The chassis is a single aluminum extrusion. No plastic bezels, no wobble, no cable mess — a single USB-C carries power, video, and data. It is the last monitor you will think about buying.', null);

INSERT INTO product (name, price, description, tax_code) VALUES ('Arc Mouse', 119.00, 'Most mice are held. This one disappears. An asymmetric shell milled from magnesium alloy, weighted to 68 grams, with a sensor accurate to 0.1mm at any speed. It does not skip. It does not drift. It goes where you tell it.

The click mechanism is a leaf spring — not a dome, not a pivot — which means the actuation is identical on the first press and the ten-thousandth. Rechargeable over USB-C, thirty hours per charge, and a braided cable included for when you cannot wait.', 'ELECTRONICS');
